<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Mini Desktop</title>
<style>
  *{box-sizing:border-box;margin:0;padding:0;font-family:sans-serif;}
  body,html{height:100%;background:#2e3436;color:white;overflow:hidden;}
  #desktop{position:absolute;width:100%;height:100%;background:url('data:image/svg+xml;base64,PHN2ZyB3aWR0aD0iMTAwJSIgaGVpZ2h0PSIxMDAlIiB4bWxucz0iaHR0cDovL3d3dy53My5vcmcvMjAwMC9zdmciPjxyZWN0IHdpZHRoPSIxMDAlIiBoZWlnaHQ9IjEwMCUiIGZpbGw9IiM1NTU1NTUiIC8+PC9zdmc+') no-repeat center/cover;}
  #taskbar{position:absolute;bottom:0;width:100%;height:40px;background:#3c3f41;border-top:1px solid #555;padding:5px 10px;display:flex;gap:10px;}
  .launcher{background:#4e5254;color:white;border:none;padding:6px 12px;border-radius:4px;cursor:pointer;}
  .window{position:absolute;background:#2e3436;border:1px solid #555;border-radius:4px;width:400px;height:300px;min-width:360px;min-height:240px;box-shadow:0 0 10px rgba(0,0,0,.5);display:none;}
  .win-header{background:#3c3f41;color:white;padding:6px;border-bottom:1px solid #555;cursor:move;display:flex;justify-content:space-between;align-items:center;}
  .win-close{background:none;border:none;color:white;font-weight:bold;cursor:pointer;}
  .content{padding:10px;height:calc(100% - 32px);overflow:auto;}
  /* Files app */
  #files-path{font-size:0.9em;margin-bottom:5px;}
  .fs-item{display:block;padding:4px 8px;border-radius:3px;cursor:pointer;}
  .fs-item:hover{background:#555;}
  /* Notepad */
  #tabs{display:flex;gap:2px;background:#3c3f41;height:30px;border-bottom:1px solid #555;}
  .tab{padding:5px 10px;background:#4e5254;color:white;cursor:pointer;border-radius:4px 4px 0 0;}
  .tab.active{background:#2e3436;}
  #new-tab{margin-left:auto;padding:5px 8px;background:#4e5254;color:white;border:none;border-radius:4px;cursor:pointer;}
  textarea#editor{width:100%;height:calc(100% - 30px);border:none;background:#2e3436;color:white;font-family:monospace;font-size:1em;padding:10px;resize:none;}
</style>
</head>
<body>
<div id="desktop">
  <div id="files-window" class="window" style="top:50px;left:50px;">
    <div class="win-header">Files<span class="win-close">&times;</span></div>
    <div class="content">
      <div id="files-path"></div>
      <button id="files-up">Up</button>
      <div id="fs-list"></div>
    </div>
  </div>

  <div id="notepad-window" class="window" style="top:70px;left:200px;">
    <div class="win-header">Notepad<span class="win-close">&times;</span></div>
    <div class="content">
      <div id="tabs"></div>
      <textarea id="editor"></textarea>
    </div>
  </div>

  <div id="taskbar">
    <button id="open-files" class="launcher">Files</button>
    <button id="open-notepad" class="launcher">Notepad</button>
  </div>
</div>

<script>
/* ---------- Files App ----------
   Simple static file system */
const fs = {
  '/': {bin:{}, etc:{}, home:{user:{Documents:{}, Downloads:{}, Pictures:{}}}, usr:{}, var:{}}
};

let currentPath = '/';

function renderFiles() {
  const pathDiv = document.getElementById('files-path');
  pathDiv.textContent = 'Path: '+currentPath;
  const list = document.getElementById('fs-list');
  list.innerHTML='';
  const parts=currentPath.split('/').filter(Boolean);
  let node=fs['/'];
  for(const p of parts) node=node[p];
  for(const key in node){
    const item=document.createElement('div');
    item.className='fs-item';
    item.textContent=key;
    if(typeof node[key]==='object'){
      item.dataset.type='folder';
      item.addEventListener('dblclick',()=>{currentPath+= (currentPath.endsWith('/')?'':'/')+key; renderFiles();});
    }else{
      item.dataset.type='file';
    }
    list.appendChild(item);
  }
}

document.getElementById('files-up').addEventListener('click',()=>{
  if(currentPath!=='/'){
    const parts=currentPath.split('/').filter(Boolean);
    parts.pop();
    currentPath='/' + parts.join('/');
    renderFiles();
  }
});

renderFiles();

/* ---------- Notepad App ----------
   Tabs persistence in localStorage */
const STORAGE_KEY='notepad_tabs';
let tabs=[];
let activeTab=0;

function loadTabs(){
  const data=localStorage.getItem(STORAGE_KEY);
  if(data) tabs=JSON.parse(data); else tabs=[{title:'Untitled',content:''}];
}
function saveTabs(){localStorage.setItem(STORAGE_KEY,JSON.stringify(tabs));}

function renderTabs(){
  const tabsDiv=document.getElementById('tabs');
  tabsDiv.innerHTML='';
  tabs.forEach((t,i)=>{
    const tabEl=document.createElement('div');
    tabEl.className='tab'+(i===activeTab?' active':'');
    tabEl.textContent=t.title;
    tabEl.addEventListener('click',()=>{activeTab=i; renderTabs(); document.getElementById('editor').value=t.content;});
    tabsDiv.appendChild(tabEl);
  });
  const newBtn=document.createElement('button');newBtn.id='new-tab';newBtn.textContent='+';
  newBtn.addEventListener('click',()=>{
    tabs.push({title:'Untitled '+(tabs.length+1),content:''});
    activeTab=tabs.length-1;
    renderTabs();
    document.getElementById('editor').value='';
    saveTabs();
  });
  tabsDiv.appendChild(newBtn);
}

const editor=document.getElementById('editor');
editor.addEventListener('input',()=>{
  tabs[activeTab].content=editor.value;
  saveTabs();
});

loadTabs(); renderTabs(); editor.value=tabs[activeTab].content;

/* ---------- Window Management ----------
   Show/Hide windows */
function showWindow(id){
  document.getElementById(id).style.display='block';
}
function hideWindow(id){
  document.getElementById(id).style.display='none';
}

document.getElementById('open-files').addEventListener('click',()=>showWindow('files-window'));
document.getElementById('open-notepad').addEventListener('click',()=>showWindow('notepad-window'));

document.querySelectorAll('.win-close').forEach(btn=>{
  btn.addEventListener('click',()=>{
    hideWindow(btn.parentNode.parentNode.id);
  });
});

/* ---------- Simple Dragging ----------
   Basic drag for windows */
let dragging=null, offsetX=0, offsetY=0;
document.querySelectorAll('.window').forEach(win=>{
  win.querySelector('.win-header').addEventListener('mousedown',e=>{
    dragging=win; offsetX=e.clientX-win.offsetLeft; offsetY=e.clientY-win.offsetTop;
    e.preventDefault();
  });
});
document.addEventListener('mousemove',e=>{
  if(dragging){
    dragging.style.left=(e.clientX-offsetX)+'px';
    dragging.style.top=(e.clientY-offsetY)+'px';
  }
});
document.addEventListener('mouseup',()=>dragging=null);
</script>
</body>
</html>
